import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.CMWvBNEy.js";const u=JSON.parse('{"title":"Scenario Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/usage/scenario-guide.md","filePath":"guide/usage/scenario-guide.md"}'),r={name:"guide/usage/scenario-guide.md"};function n(s,e,l,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="scenario-guide" tabindex="-1">Scenario Guide <a class="header-anchor" href="#scenario-guide" aria-label="Permalink to &quot;Scenario Guide&quot;">​</a></h1><p>Scenarios allow you to group multiple handler configurations into a single set for easy storage and management. You can reproduce complex test environments with just a single click.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Save Scenarios</strong>: Save current handler variants, delays, and other settings as a scenario.</li><li><strong>One-Click Apply</strong>: Instantly apply all handler configurations included in a saved scenario.</li><li><strong>Status Syncing</strong>: View the <code>Active</code> status in the list when a scenario is enabled.</li><li><strong>Share &amp; Export</strong>: Copy scenario JSON data to share with teammates, or export/import them as files.</li></ul><h2 id="scenario-status" tabindex="-1">Scenario Status <a class="header-anchor" href="#scenario-status" aria-label="Permalink to &quot;Scenario Status&quot;">​</a></h2><ul><li><strong>Active Status</strong>: When a scenario is applied, an <code>Active</code> badge appears next to its name. This status is maintained as long as at least one handler in the scenario is active.</li><li><strong>Inactive Status</strong>: A scenario becomes inactive if all its handlers are deactivated or if a different scenario is applied.</li></ul><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><ol><li><p>Open the Mocking GUI Panel.</p></li><li><p>Configure the state (Response Variant, Delay, etc.) of the handlers you want to batch process, then click the <strong>+ (Add)</strong> icon on the handler to register it to the scenario draft list.</p></li><li><p>Go to the <strong>Scenarios</strong> tab.</p></li><li><p>Enter a scenario name and click the <strong>+ (Add)</strong> button to save.</p></li><li><p><strong>Draft Bar</strong>:</p><ul><li>Selecting a variant from the handler list brings up the Draft Bar at the bottom.</li><li><strong>Expanded View</strong>: Click the arrow on the left of the Draft Bar to preview the list of APIs included in the current draft.</li><li><strong>Clear Draft</strong>: Click the <code>Clear All</code> button to remove all currently selected handlers from the draft.</li></ul></li><li><p><strong>Save Scenario</strong>: Enter a name for the scenario and click Save to add it to the Scenario tab.</p></li><li><p><strong>Apply &amp; Deactivate</strong>: Click &#39;Apply&#39; on a scenario card to enable it, or &#39;Deactivate&#39; to disable it.</p></li></ol><h2 id="exporting-importing-scenarios" tabindex="-1">Exporting &amp; Importing Scenarios <a class="header-anchor" href="#exporting-importing-scenarios" aria-label="Permalink to &quot;Exporting &amp; Importing Scenarios&quot;">​</a></h2><ul><li><strong>Export JSON File</strong>: Click the &#39;Export&#39; button at the top of the Scenario tab to download all saved scenarios as a <code>.json</code> file.</li><li><strong>Import File</strong>: Upload a JSON file in the &#39;Import&#39; section to register multiple scenarios at once.</li><li><strong>Direct JSON Input (Share)</strong>: Click the share button on an individual scenario card to copy its JSON data. Paste this data into the Textarea in the &#39;Import&#39; section to register it instantly.</li></ul>',10)])])}const g=t(r,[["render",n]]);export{u as __pageData,g as default};
